INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Writer', 'writer-ai', 'Enterprise AI platform for content generation', 'Writer is an enterprise AI platform that generates on-brand content at scale. Build custom AI apps, enforce brand guidelines, and connect to your knowledge graph for accurate, consistent outputs across marketing, support, and operations.', 'https://writer.com', 'enterprise', '[{"plan":"Team","price":"$18/user/mo","features":["AI writing","Brand voice"]},{"plan":"Enterprise","price":"Custom","features":["Custom models","Knowledge graph","API"]}]', 'beginner', true, '{web,api}', '{"On-brand content","Knowledge graph","Custom AI apps","Brand voice enforcement","Templates","Style guide","Terminology management","Content brief generation"}', '{"Chrome","Google Docs","Figma","Contentful","HubSpot","Salesforce"}', 'https://developer.writer.com', true, '{"Enterprise marketing teams","Brand-conscious organizations","Content teams at scale"}', '{"Individual writers","Creative fiction"}', 'The best enterprise content AI; knowledge graph integration means outputs actually sound like your brand, not generic AI.', now()),
('Writesonic', 'writesonic', 'AI content creation platform for marketers', 'Writesonic provides AI-powered content generation for articles, ads, landing pages, and social media. Features include Chatsonic (AI chat with web access), Botsonic (custom chatbots), and bulk content generation.', 'https://writesonic.com', 'freemium', '[{"plan":"Free","price":"$0","features":["10,000 words/mo"]},{"plan":"Individual","price":"$16/mo","features":["Unlimited words","All features"]},{"plan":"Team","price":"$13/user/mo","features":["Collaboration","Brand voice"]}]', 'beginner', true, '{web,api}', '{"Article generation","Ad copy","Landing pages","Chatsonic (AI chat)","Botsonic (custom bots)","Bulk generation","SEO optimization","Brand voice","100+ templates"}', '{"WordPress","Zapier","Google Docs","Semrush","Surfer SEO"}', 'https://docs.writesonic.com', true, '{"Content marketers","SEO writers","Ad copywriters"}', '{"Technical documentation","Academic writing"}', 'Strong all-rounder for marketing content with Chatsonic as a solid ChatGPT alternative; the SEO integration saves time.', now()),
('Wordtune', 'wordtune', 'AI writing companion that refines your words', 'Wordtune by AI21 Labs helps you rewrite and refine existing text. It suggests alternative phrasings, adjusts tone, shortens or expands text, and translates — preserving your meaning while improving clarity.', 'https://wordtune.com', 'freemium', '[{"plan":"Free","price":"$0","features":["10 rewrites/day"]},{"plan":"Plus","price":"$10/mo","features":["Unlimited rewrites","Summaries"]},{"plan":"Business","price":"$14/user/mo","features":["Team features","Brand tone"]}]', 'beginner', false, '{web}', '{"Text rewriting","Tone adjustment","Shorten/expand","Translation","Summarization","Chrome extension","Microsoft Word add-in","Multiple suggestions"}', '{"Chrome","Microsoft Word","Google Docs","Email clients"}', 'https://wordtune.com/blog', true, '{"Non-native English speakers","Business email writers","Students improving essays"}', '{"First-draft content generation"}', 'The best tool for making existing text better; excels at preserving your voice while improving clarity and concision.', now()),
('Descript', 'descript', 'AI-powered video and podcast editing', 'Descript makes video and podcast editing as easy as editing a document. Transcribe, edit by deleting text, generate AI voices, remove filler words, and produce studio-quality content without traditional editing skills.', 'https://descript.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1hr transcription/mo"]},{"plan":"Hobbyist","price":"$24/mo","features":["10hrs transcription","AI tools"]},{"plan":"Pro","price":"$33/mo","features":["30hrs transcription","4K export"]}]', 'beginner', true, '{desktop,web}', '{"Text-based video editing","Transcription","Filler word removal","AI voice cloning","Screen recording","Eye contact correction","Green screen","Studio Sound","Clips"}', '{"YouTube","Spotify","Apple Podcasts","Google Drive","Slack"}', 'https://help.descript.com', true, '{"Podcasters","YouTubers","Corporate video teams","Content repurposers"}', '{"Professional film editors"}', 'Revolutionary approach to video editing — editing text to edit video is genuinely magical. Eye contact and Studio Sound are killer features.', now()),
('Opus Clip', 'opus-clip', 'AI-powered short video clips from long content', 'Opus Clip uses AI to find the most engaging moments in long videos and turns them into viral short-form clips for TikTok, Reels, and Shorts. Features AI-powered reframing, captions, and virality scoring.', 'https://opus.pro', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited exports"]},{"plan":"Starter","price":"$15/mo","features":["200 min upload/mo"]},{"plan":"Pro","price":"$29/mo","features":["600 min upload/mo","Priority"]}]', 'beginner', false, '{web}', '{"Long-to-short clipping","AI curation","Virality score","Auto-captions","Active speaker tracking","Dynamic reframing","B-roll suggestions","Brand kit","Batch processing"}', '{"YouTube","TikTok","Instagram","Google Drive","Zoom"}', 'https://help.opus.pro', true, '{"YouTubers repurposing content","Social media managers","Podcast hosts creating clips"}', '{"Original short-form content creation"}', 'The best tool for repurposing long videos; the AI virality scoring is surprisingly accurate at picking engaging moments.', now()),
('Heygen', 'heygen', 'AI avatar video creation platform', 'HeyGen generates professional videos with AI avatars and voices. Choose from 200+ avatars, clone your own appearance and voice, and create talking-head videos in 175+ languages without cameras or studios.', 'https://heygen.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 free credit"]},{"plan":"Creator","price":"$24/mo","features":["15 min video/mo"]},{"plan":"Business","price":"$72/mo","features":["30 min video/mo","Priority"]}]', 'beginner', true, '{web,api}', '{"200+ AI avatars","Voice cloning","175+ languages","Avatar cloning","Video translation","Interactive avatars","Templates","Streaming API","Personalized videos"}', '{"Zapier","HubSpot","Salesforce","API integration"}', 'https://docs.heygen.com', true, '{"Corporate training teams","Marketing at scale","Multilingual content creators"}', '{"Authentic personal branding"}', 'Leading AI avatar platform with the most natural-looking avatars; video translation feature alone can justify the cost for global teams.', now()),
('Canva AI', 'canva-ai', 'AI-powered design for everyone', 'Canva''s AI features include Magic Design (auto-layouts), Magic Write (text generation), Background Remover, Magic Eraser, Text to Image, and more — all inside the world''s most popular design platform.', 'https://canva.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Basic AI features","250K+ templates"]},{"plan":"Pro","price":"$13/mo","features":["All AI features","Brand Kit"]},{"plan":"Teams","price":"$10/user/mo","features":["Collaboration","Approvals"]}]', 'beginner', false, '{web,mobile,desktop}', '{"Magic Design","Magic Write","Text to Image","Background Remover","Magic Eraser","Magic Animate","Brand Kit","Translation","Bulk create","Magic Switch"}', '{"Google Drive","Dropbox","HubSpot","Mailchimp","Shopify","Slack","YouTube"}', 'https://canva.com/designschool', true, '{"Non-designers creating professional content","Social media managers","Small business owners"}', '{"Professional print designers","Complex illustration work"}', 'AI features make the already-dominant design tool even more accessible; Magic Design and Background Remover save real time daily.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Figma AI', 'figma-ai', 'AI-powered design features inside Figma', 'Figma AI brings generative design capabilities directly into Figma''s design tool. Features include AI-powered layout suggestions, asset search, text generation, layer renaming, and prototype creation from text descriptions.', 'https://figma.com/ai', 'freemium', '[{"plan":"Starter","price":"$0","features":["3 projects","Basic AI"]},{"plan":"Professional","price":"$15/editor/mo","features":["All AI features","Libraries"]},{"plan":"Organization","price":"$45/editor/mo","features":["SSO","Analytics","Branching"]}]', 'intermediate', true, '{web,desktop}', '{"AI layout suggestions","Visual search","Text generation","Layer rename","Remove background","Auto-translate","Prototype from text","First Draft"}', '{"Slack","Jira","Storybook","GitHub","VS Code","Zeplin","Notion"}', 'https://help.figma.com', true, '{"UI/UX designers","Product teams","Design system managers"}', '{"Non-design tasks"}', 'AI features feel native rather than bolted-on; First Draft for generating initial layouts from prompts is a genuine time-saver.', now()),
('Galileo AI', 'galileo-ai', 'AI-powered UI generation from text', 'Galileo AI generates high-fidelity UI designs from natural language descriptions. It creates complete screens with real content, proper hierarchy, and design system compliance — exportable to Figma.', 'https://usegalileo.ai', 'paid', '[{"plan":"Pro","price":"$19/mo","features":["Unlimited generations","Figma export"]},{"plan":"Team","price":"Custom","features":["Collaboration","Design system"]}]', 'intermediate', false, '{web}', '{"Text-to-UI","High-fidelity output","Figma export","Real content generation","Responsive layouts","Design system compliance","Component library","Rapid iteration"}', '{"Figma","Design systems"}', 'https://usegalileo.ai/docs', true, '{"Designers needing quick mockups","Product managers prototyping","Startups validating UI ideas"}', '{"Pixel-perfect production design"}', 'Impressive for initial UI exploration and mockup generation; the quality has improved dramatically since launch.', now()),
('Framer', 'framer', 'AI-powered website builder for designers', 'Framer is a professional website builder with AI-powered features. Generate entire sites from text descriptions, add animations and interactions, and publish with CMS and localization — no code required.', 'https://framer.com', 'freemium', '[{"plan":"Free","price":"$0","features":["framer.site domain","1 CMS collection"]},{"plan":"Mini","price":"$5/mo","features":["Custom domain","Basic analytics"]},{"plan":"Basic","price":"$15/mo","features":["CMS","Password protection"]},{"plan":"Pro","price":"$25/mo","features":["Advanced CMS","Localization"]}]', 'intermediate', false, '{web}', '{"AI website generation","Visual builder","CMS","Localization","Custom animations","Interactions","Responsive design","SEO tools","Code components","Forms"}', '{"Google Analytics","Zapier","Mailchimp","HubSpot","Notion","Airtable"}', 'https://framer.com/academy', true, '{"Designers building marketing sites","Startups needing fast websites","Agencies delivering client sites"}', '{"Complex web applications","E-commerce"}', 'The most designer-friendly website builder with genuine AI generation; animations and interactions are best-in-class.', now()),
('Uizard', 'uizard', 'AI design tool for non-designers', 'Uizard transforms wireframes, screenshots, and text descriptions into polished UI designs. Upload a sketch on paper, and Uizard converts it to an interactive prototype with AI-generated content and styling.', 'https://uizard.io', 'freemium', '[{"plan":"Free","price":"$0","features":["3 projects","Basic AI"]},{"plan":"Pro","price":"$12/mo","features":["Unlimited projects","All AI features"]},{"plan":"Business","price":"$39/mo","features":["Team features","Brand kit"]}]', 'beginner', false, '{web}', '{"Sketch-to-design","Screenshot-to-design","Text-to-design","Interactive prototypes","Design themes","Collaboration","Export to code","Heatmap predictions"}', '{"Figma (export)","Sketch (export)"}', 'https://uizard.io/blog', true, '{"Product managers prototyping","Non-designers creating mockups","Early-stage startups"}', '{"Professional UI designers"}', 'Perfect for non-designers who need to communicate ideas visually; the sketch-to-design feature is genuinely impressive.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Airplane', 'airplane', 'Internal tools and workflows for engineering teams', 'Airplane provides a platform for building internal tools, runbooks, and workflows. Create UIs connected to databases and APIs, build approval flows, and schedule tasks — purpose-built for engineering and operations teams.', 'https://airplane.dev', 'freemium', '[{"plan":"Free","price":"$0","features":["5 users","Unlimited tasks"]},{"plan":"Team","price":"$10/user/mo","features":["SSO","Audit logs"]},{"plan":"Enterprise","price":"Custom","features":["Dedicated infra","Custom SLA"]}]', 'intermediate', true, '{web,api}', '{"Task automation","Runbooks","Approval workflows","SQL + REST tasks","Scheduling","Parameter forms","Audit logs","Role-based access","Views (dashboards)"}', '{"PostgreSQL","MySQL","MongoDB","REST APIs","Slack","GitHub","PagerDuty"}', 'https://docs.airplane.dev', true, '{"Engineering teams building internal tools","DevOps teams","Platform engineering"}', '{"Non-technical teams"}', 'Excellent developer-focused internal tool platform; runbooks and approval workflows are cleaner than Retool for ops use cases.', now()),
('Spacelift', 'spacelift', 'Infrastructure as Code management with AI', 'Spacelift manages Infrastructure as Code at scale with policy-as-code, drift detection, and AI-suggested remediations. Supports Terraform, OpenTofu, Pulumi, CloudFormation, and Kubernetes.', 'https://spacelift.io', 'freemium', '[{"plan":"Free","price":"$0","features":["1 worker","Community support"]},{"plan":"Cloud","price":"Custom","features":["Managed workers","SSO","Policies"]},{"plan":"Enterprise","price":"Custom","features":["Self-hosted","RBAC","Audit"]}]', 'advanced', true, '{web,api,cli}', '{"Multi-IaC support","Policy as code","Drift detection","AI remediation","Stack dependencies","Approval workflows","Audit trails","Custom runners","Module registry"}', '{"Terraform","Pulumi","CloudFormation","Kubernetes","AWS","Azure","GCP","GitHub","GitLab"}', 'https://docs.spacelift.io', true, '{"Platform engineering teams","DevOps managing multi-cloud","Enterprise IaC operations"}', '{"Small teams with simple infra"}', 'The most comprehensive IaC management platform; policy-as-code governance is essential for enterprise cloud operations.', now()),
('LinearB', 'linearb', 'AI-powered engineering management platform', 'LinearB provides engineering metrics, workflow automation, and AI-driven insights for development teams. Track cycle time, review bottlenecks, and automate engineering workflows with data-driven decisions.', 'https://linearb.io', 'freemium', '[{"plan":"Free","price":"$0","features":["Basic metrics","5 contributors"]},{"plan":"Team","price":"Custom","features":["All metrics","Automation"]},{"plan":"Enterprise","price":"Custom","features":["Custom metrics","SSO"]}]', 'intermediate', true, '{web,api}', '{"Engineering metrics","Cycle time tracking","PR bottleneck detection","Workflow automation","Team insights","Retrospective data","Investment profiles","GitStream"}', '{"GitHub","GitLab","Bitbucket","Jira","Slack","Linear"}', 'https://docs.linearb.io', true, '{"Engineering managers","VP Engineering","DevOps leads tracking velocity"}', '{"Individual developers","Non-engineering teams"}', 'Best engineering metrics platform with actionable insights; GitStream for automating PR workflows is a standout feature.', now()),
('Kubecost', 'kubecost', 'Kubernetes cost monitoring and optimization', 'Kubecost provides real-time cost monitoring and optimization for Kubernetes clusters. See granular cost allocation by pod, service, and team, get savings recommendations, and set budgets with AI-driven alerts.', 'https://kubecost.com', 'freemium', '[{"plan":"Free","price":"$0","features":["1 cluster","15 day retention"]},{"plan":"Business","price":"Custom","features":["Multi-cluster","90 day retention","SSO"]},{"plan":"Enterprise","price":"Custom","features":["Unlimited retention","Priority"]}]', 'advanced', true, '{web,api,cli}', '{"Cost allocation","Savings recommendations","Budget alerts","Right-sizing","Cluster efficiency","Multi-cluster support","Cost anomaly detection","Showback/chargeback"}', '{"AWS","Azure","GCP","Kubernetes","Prometheus","Grafana","Datadog","Terraform"}', 'https://docs.kubecost.com', true, '{"Platform engineering teams","FinOps practitioners","K8s operators controlling spend"}', '{"Non-Kubernetes workloads"}', 'Essential for any team running Kubernetes at scale; typical customers save 30-50% on cloud spend after implementing recommendations.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Stripe Radar', 'stripe-radar', 'AI-powered fraud detection for payments', 'Stripe Radar uses machine learning trained on billions of transactions to detect and block fraud in real-time. Adaptive algorithms learn from global patterns, and custom rules let you fine-tune protection.', 'https://stripe.com/radar', 'freemium', '[{"plan":"Included","price":"$0","features":["Basic fraud detection (included with Stripe)"]},{"plan":"Radar for Fraud Teams","price":"$0.07/transaction","features":["Custom rules","Manual reviews","Advanced analytics"]}]', 'intermediate', true, '{web,api}', '{"ML fraud detection","Real-time scoring","Custom rules","Manual review queues","3D Secure integration","Block lists","Dispute management","Risk insights"}', '{"Stripe Payments","Stripe Billing","Stripe Connect","Stripe Terminal"}', 'https://stripe.com/docs/radar', true, '{"Any business using Stripe","E-commerce","SaaS billing teams"}', '{"Non-Stripe payment processors"}', 'The gold standard for payment fraud detection; included free with Stripe means there''s no reason not to use it.', now()),
('Ramp', 'ramp', 'AI-powered corporate spend management', 'Ramp is a corporate card and spend management platform that uses AI to save companies money. Automated expense reports, duplicate subscription detection, real-time budgets, and AI-powered receipt matching.', 'https://ramp.com', 'free', '[{"plan":"Free","price":"$0","features":["Corporate cards","Expense management","Bill pay","AI features"]}]', 'beginner', true, '{web,mobile,api}', '{"Corporate cards","AI expense categorization","Duplicate detection","Receipt matching","Budget management","Bill pay","Procurement","Price intelligence","Accounting sync"}', '{"QuickBooks","Xero","NetSuite","Sage","Slack","Okta","AWS","Google Workspace"}', 'https://docs.ramp.com', true, '{"Startups managing spend","Finance teams","Companies wanting free expense management"}', '{"Individual freelancers","Non-US businesses"}', 'Genuinely free and saves companies an average of 5% on total spend; the AI duplicate subscription finder pays for itself immediately.', now()),
('Brex', 'brex', 'AI-powered financial operations for growing companies', 'Brex provides corporate cards, expense management, bill pay, and travel — unified with AI for financial operations. Auto-categorization, policy enforcement, and real-time spend visibility for startups and enterprises.', 'https://brex.com', 'freemium', '[{"plan":"Essentials","price":"$0","features":["Corporate cards","Basic expense management"]},{"plan":"Premium","price":"$12/user/mo","features":["Advanced budgets","Bill pay","Travel"]},{"plan":"Enterprise","price":"Custom","features":["Custom policies","ERP sync"]}]', 'beginner', true, '{web,mobile,api}', '{"Corporate cards","AI categorization","Policy enforcement","Bill pay","Travel management","Reimbursements","Budget controls","ERP integration","Empower (AI assistant)"}', '{"NetSuite","QuickBooks","Xero","Slack","Okta","Rippling","Workday"}', 'https://developer.brex.com', true, '{"VC-backed startups","Scaling companies","Finance teams needing unified platform"}', '{"Very small businesses","Personal finance"}', 'The default corporate card for startups with good reason; Empower AI assistant makes expense management nearly autonomous.', now()),
('Stamped', 'stamped', 'AI-powered tax automation for crypto', 'Stamped (formerly TaxBit) provides AI-powered cryptocurrency tax reporting and compliance. Automatically calculates gains, generates tax forms, and ensures compliance across thousands of tokens and exchanges.', 'https://stamped.ai', 'freemium', '[{"plan":"Free","price":"$0","features":["Up to 25 transactions"]},{"plan":"Plus","price":"$50/year","features":["1000 transactions"]},{"plan":"Pro","price":"$175/year","features":["Unlimited transactions","Tax-loss harvesting"]}]', 'beginner', false, '{web}', '{"Crypto tax calculation","Auto-import transactions","Tax form generation","Tax-loss harvesting","Multi-exchange support","DeFi tracking","NFT tracking","Portfolio analytics"}', '{"Coinbase","Binance","Kraken","MetaMask","Phantom","100+ exchanges"}', 'https://help.stamped.ai', true, '{"Crypto traders","DeFi users","Tax professionals handling crypto clients"}', '{"Traditional investment tax needs"}', 'Essential for anyone trading crypto; auto-import from exchanges and DeFi tracking save hours during tax season.', now())
INSERT INTO tools (name, slug, tagline, description, website_url, pricing_type, pricing_details, skill_level, has_api, platforms, features, integrations, docs_url, is_published, best_for, not_for, editorial_verdict, last_verified_at) VALUES
('Elicit', 'elicit', 'AI research assistant for academic papers', 'Elicit uses AI to help researchers find, summarize, and extract data from academic papers. Search across 125M+ papers, get AI-generated summaries, and build systematic reviews with automated data extraction.', 'https://elicit.com', 'freemium', '[{"plan":"Basic","price":"$0","features":["5,000 paper summaries/mo"]},{"plan":"Plus","price":"$12/mo","features":["Unlimited summaries","Data extraction"]},{"plan":"Enterprise","price":"Custom","features":["API access","Custom workflows"]}]', 'intermediate', true, '{web}', '{"Semantic paper search","AI summaries","Data extraction","Systematic reviews","Citation export","125M+ papers","Find contradictions","Research synthesis"}', '{"Zotero","Google Scholar","BibTeX export"}', 'https://support.elicit.com', true, '{"Academic researchers","PhD students","Systematic review teams"}', '{"Non-academic research"}', 'The most useful AI research tool for academics; data extraction across papers is genuinely transformative for lit reviews.', now()),
('Scholarcy', 'scholarcy', 'AI-powered research paper summarizer', 'Scholarcy reads and summarizes research papers, reports, and book chapters into structured flashcards. Extracts key findings, methods, limitations, and references — saving hours of reading time.', 'https://scholarcy.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Article summaries"]},{"plan":"Personal","price":"$9.99/mo","features":["Full library","Chrome extension"]},{"plan":"Institutional","price":"Custom","features":["Team access","API"]}]', 'beginner', false, '{web}', '{"Paper summarization","Flashcard generation","Key finding extraction","Method identification","Reference extraction","Chrome extension","Library management","Batch processing"}', '{"Zotero","Mendeley","Chrome","Word"}', 'https://scholarcy.com/support', true, '{"Students reading papers","Researchers doing literature reviews","Professionals staying current"}', '{"Primary research writing"}', 'Excellent for quickly understanding papers you need to read but don''t have time for; flashcard format is surprisingly effective.', now()),
('Photomath', 'photomath', 'AI math problem solver with step-by-step explanations', 'Photomath uses AI to solve math problems from photos and typed input. It provides step-by-step explanations, multiple solution methods, and animated tutorials — making it the world''s most popular math learning app.', 'https://photomath.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Basic solutions","Calculator"]},{"plan":"Plus","price":"$10/mo","features":["Step-by-step explanations","Animated tutorials","Multiple methods"]}]', 'beginner', false, '{mobile}', '{"Photo-to-solution","Step-by-step explanations","Animated tutorials","Multiple solution methods","Graphing","Scientific calculator","Handwriting recognition","30+ languages"}', '{}', 'https://photomath.com/articles', true, '{"Students learning math","Parents helping with homework","Self-study learners"}', '{"Advanced university mathematics"}', 'Best math learning app for K-12; the step-by-step explanations actually teach rather than just giving answers.', now()),
('Synthesis AI', 'synthesis-tutor', 'AI math tutor for kids that builds problem-solving skills', 'Synthesis Tutor uses AI to create personalized math challenges that build problem-solving skills. Originally created for SpaceX families, it adapts difficulty in real-time and focuses on mathematical thinking over rote memorization.', 'https://synthesis.com', 'paid', '[{"plan":"Monthly","price":"$25/mo","features":["Personalized lessons","Progress tracking"]},{"plan":"Annual","price":"$192/year","features":["All features","Save 36%"]}]', 'beginner', false, '{web,mobile}', '{"Adaptive difficulty","Problem-solving focus","Real-time personalization","Progress tracking","Mathematical reasoning","Competition mode","Parent dashboard","Gamified learning"}', '{}', 'https://synthesis.com/tutor', true, '{"Parents wanting math enrichment","Gifted students","Kids ages 6-14"}', '{"Test prep","Adult math learning"}', 'The most engaging math program for kids; focuses on building mathematical intuition rather than drilling procedures.', now()),
('Speak', 'speak', 'AI language tutor with realistic conversation practice', 'Speak is an AI-powered language learning app focused on speaking practice. Have realistic conversations with AI tutors, get pronunciation feedback, and build fluency through interactive scenarios — not flashcards.', 'https://speak.com', 'paid', '[{"plan":"Premium","price":"$14/mo","features":["Unlimited conversations","All lessons"]},{"plan":"Premium Plus","price":"$25/mo","features":["Advanced features","Review sessions"]}]', 'beginner', false, '{mobile}', '{"AI conversation practice","Pronunciation feedback","Speaking-first approach","Roleplay scenarios","Grammar explanations","Progress tracking","Multiple languages","Voice recognition"}', '{}', 'https://speak.com/blog', true, '{"Language learners wanting speaking practice","Professionals learning business language","Travelers preparing for trips"}', '{"Reading/writing focused learners"}', 'The best AI language app for speaking fluency; conversation-first approach builds confidence that flashcard apps can''t match.', now()),
('Quillbot', 'quillbot', 'AI paraphrasing and writing enhancement tool', 'QuillBot helps writers paraphrase, check grammar, summarize, and translate text. Its paraphraser offers multiple modes (fluency, formal, creative) and integrates directly into Chrome and Microsoft Word.', 'https://quillbot.com', 'freemium', '[{"plan":"Free","price":"$0","features":["125-word paraphrase","Grammar check"]},{"plan":"Premium","price":"$10/mo","features":["Unlimited words","All modes","Plagiarism checker"]}]', 'beginner', false, '{web}', '{"Paraphrasing (7 modes)","Grammar checker","Summarizer","Citation generator","Translator","Plagiarism checker","Chrome extension","Word add-in","Co-Writer"}', '{"Chrome","Microsoft Word","Google Docs","macOS"}', 'https://quillbot.com/blog', true, '{"Students writing essays","ESL writers","Professionals improving emails"}', '{"Creative writers wanting original voice"}', 'The most popular paraphrasing tool for good reason; multiple modes give genuine variety unlike simple synonym swaps.', now())
